#!/usr/bin/env python3
"""
Full Japanese translation of all boki2 quiz files.
Each file gets complete hand-translated questions and options.
Explanations (already in Japanese) are kept as-is.
"""

import json
import os

DATA_DIR = r"C:\Users\haro\.openclaw\workspace\boki2-study\src\data"

# Read original files to preserve explanations and correct flags
def read_original(filename):
    path = os.path.join(DATA_DIR, filename)
    with open(path, 'r', encoding='utf-8') as f:
        return json.load(f)

def write_file(filename, data):
    path = os.path.join(DATA_DIR, filename)
    with open(path, 'w', encoding='utf-8') as f:
        json.dump(data, f, ensure_ascii=False, indent=2)

# Build translated data by replacing question/options text while keeping explanation and correct flags
def build_translated(orig_data, translations):
    """translations is a list of dicts with 'question' and 'options' (list of text strings, in order)"""
    result = []
    for i, item in enumerate(orig_data):
        t = translations[i]
        new_item = {
            "category": t.get("category", item.get("category", "")),
            "question": t["question"],
            "options": [],
            "explanation": item["explanation"]
        }
        for j, orig_opt in enumerate(item["options"]):
            new_item["options"].append({
                "text": t["options"][j],
                "correct": orig_opt["correct"]
            })
        # Copy extra fields like 'steps'
        for key in ["steps"]:
            if key in item:
                new_item[key] = item[key]
        result.append(new_item)
    return result

